      <OrderList orders={orders} onUpdateOrderStatus={updateOrderStatus} />
      
      {/* مودال التعليقات */}
      {showCommentsList && (
        <div className="modal-overlay" onClick={() => setShowCommentsList(false)}>
          <div className="modal-content-group" onClick={(e) => e.stopPropagation()}>
            <button onClick={() => setShowCommentsList(false)} className="close-btn">✕</button>
            <h2 className="text-white text-center text-xl">Commentaires</h2>
            <button onClick={() => setShowAddComment(true)} className="btn-livre-all w-full my-4">✏️ Écrire</button>
            {comments.map(c => (
              <div key={c.id} className="detail-order-item">
                <div><b className="text-white">{c.author}</b><p className="text-gray-400 text-sm">{c.text}</p></div>
              </div>
            ))}
          </div>
        </div>
      )}
      
      {showAddComment && (
        <div className="modal-overlay" onClick={() => setShowAddComment(false)}>
          <div className="modal-content-group" onClick={(e) => e.stopPropagation()}>
            <button onClick={() => setShowAddComment(false)} className="close-btn">✕</button>
            <input type="text" className="w-full p-3 rounded-xl bg-white/10 text-white mb-3" 
              placeholder="Nom" value={newComment.author} 
              onChange={(e) => setNewComment({...newComment, author: e.target.value})} />
            <textarea className="w-full p-3 rounded-xl bg-white/10 text-white" rows="3"
              placeholder="Commentaire" value={newComment.text}
              onChange={(e) => setNewComment({...newComment, text: e.target.value})} />
            <button onClick={addComment} className="btn-livre-all w-full mt-4">Publier</button>
          </div>
        </div>
      )}
      
      <Footer />
    </>
  );
}
